package com.databricks.dicer.external.javaapi;

import com.databricks.conf.RawConfigSingleton;
import com.databricks.dicer.client.javaapi.SliceletConfImpl;

import com.google.common.collect.ImmutableList;
import com.google.common.collect.ImmutableSet;
import com.typesafe.config.Config;
import java.util.Optional;
import java.util.concurrent.CompletionStage;
import scala.collection.JavaConverters;
import scala.compat.java8.FutureConverters;
import scala.compat.java8.OptionConverters;

/**
 * This is a test environment for applications to test against Dicer.
 *
 * <p>It is strongly recommended that the test code create a single {@link DicerTestEnvironment} for
 * the entire test suite rather than creating a new one for each test, but use a different {@link
 * Target} in each test to avoid interference between test cases.
 *
 * <p>At the end of each test, stop the Slicelets/Clerks created for that test to avoid resource
 * leaks and interference between tests.
 *
 * <p>Example usage:
 *
 * <pre>{@code
 * public class MySuiteTest extends DatabricksJavaTest {
 *   private static final DicerTestEnvironment testEnv = DicerTestEnvironment.create();
 *
 *   @BeforeAll
 *   static void beforeAll() {
 *     // Required for Slicelet and Clerk creation.
 *     CurrentProject.initializeProject(Project.TestProject());
 *   }
 *
 *   // Environment should be stopped after all tests are done.
 *   @AfterAll
 *   public void tearDown() {
 *     env.stop();
 *   }
 *
 *   @Test
 *   public void testHelloDicer() {
 *     Target target = new Target("hello_dicer_target");
 *     Slicelet slicelet = testEnv.createSlicelet(target);
 *     ClerkConfig.Builder clerkConfigBuilder = ClerkConfig.builder();
 *     // Inject connection config into the caller config so that the clerk can communicate with
 *     // the specified slicelet.
 *     testEnv.setConnectionConfigForNewClerk(clerkConfigBuilder, slicelet);
 *     Clerk<ResourceAddress> clerk =
 *       Clerk.create(clerkConfigBuilder.build(), target, "localhost", Function.identity());
 *     // ...
 *     testEnv.stopSlicelet(slicelet);
 *     testEnv.stopClerk(clerk);
 *   }
 *
 *   @Test
 *   public void testHelloDicerAgain() {
 *     Target target = new Target("hello_dicer_again_target");
 *     Slicelet slicelet = testEnv.createSlicelet(target);
 *     ClerkConfig.Builder clerkConfigBuilder = ClerkConfig.builder();
 *     testEnv.setConnectionConfigForNewClerk(clerkConfigBuilder, slicelet);
 *     clerkConfigBuilder.setSliceletPort(8080);
 *     Clerk<ResourceAddress> clerk =
 *       Clerk.create(clerkConfigBuilder.build(), target, "localhost", Function.identity());
 *     // ...
 *     testEnv.stopSlicelet(slicelet);
 *     testEnv.stopClerk(clerk);
 *   }
 * }
 * }</pre>
 *
 * <p>This environment has two modes - regular mode and frozen mode. In the former case, the system
 * works normally where the assignment is generated by Dicer and pushed to all Slicelets/Clerks. In
 * the frozen case, the assignment is provided by the caller using {@link #setAndFreezeAssignment} -
 * that particular assignment is then propagated to all Slicelets/Clerks. The former allows testing
 * as the system would run in production and the latter allows controlled placement of slices for
 * specific tests.
 *
 * <p>The caller must not assume that each Slicelet/Clerk has received the assignment after {@link
 * #setAndFreezeAssignment} returns. They will receive the assignment eventually.
 */
// This is a Java wrapper for the Scala DicerTestEnvironment that provides a convenient API for Java
// tests.
public final class DicerTestEnvironment {

  /** The underlying Scala DicerTestEnvironment. */
  private final com.databricks.dicer.external.DicerTestEnvironment scalaTestEnv;

  /** Private constructor - use factory methods to create instances. */
  private DicerTestEnvironment(com.databricks.dicer.external.DicerTestEnvironment scalaTestEnv) {
    this.scalaTestEnv = scalaTestEnv;
  }

  /** Creates a new DicerTestEnvironment. */
  public static DicerTestEnvironment create() {
    // We don't currently have use cases that need setting tlsFilePathsOpt and sliceletHostNameOpt
    // explicitly, so we pass empty Optional values for both parameters.
    com.databricks.dicer.external.DicerTestEnvironment scalaEnv =
        com.databricks.dicer.external.DicerTestEnvironment.create(
            OptionConverters.toScala(Optional.empty()), // tlsFilePathsOpt
            OptionConverters.toScala(Optional.empty())); // sliceletHostNameOpt
    return new DicerTestEnvironment(scalaEnv);
  }

  /**
   * Creates a new Slicelet that communicates with the Assigner in the test environment.
   *
   * @param target the Target this Slicelet belongs to.
   */
  public Slicelet createSlicelet(Target target) {
    // Get the test environment connection config for the Assigner and inject it into the Slicelet.
    // This allows the Slicelet to communicate with the test Assigner.
    Config testEnvConfig = scalaTestEnv.getConnectionConfigForNewSlicelet();
    Config mergedConfig = testEnvConfig.withFallback(RawConfigSingleton.conf());
    SliceletConfImpl sliceletConf = DicerClientConfTestFactory.createSliceletConf(mergedConfig);
    return Slicelet.createForTest(sliceletConf, target);
  }

  /**
   * Injects connection config for a new Clerk that communicates with the given Slicelet into the
   * caller-provided config builder and returns that same builder.
   */
  public ClerkConfig.Builder setConnectionConfigForNewClerk(
      ClerkConfig.Builder configBuilder, Slicelet slicelet) {
    Config testEnvConfig = scalaTestEnv.getConnectionConfigForNewClerk(slicelet.toScala());
    DicerClientConfTestFactory.setClerkBaseConf(configBuilder.toScalaForTest(), testEnvConfig);
    return configBuilder;
  }

  /**
   * @see com.databricks.dicer.external.DicerTestEnvironment#setAndFreezeAssignment
   */
  public TestAssignmentHandle setAndFreezeAssignment(
      Target target,
      com.databricks.dicer.external.DicerTestEnvironment.TestAssignment testAssignment) {
    com.databricks.dicer.external.DicerTestEnvironment.AssignmentHandle scalaHandle =
        scalaTestEnv.setAndFreezeAssignment(target.toScala(), testAssignment);
    return new TestAssignmentHandle(scalaHandle);
  }

  /**
   * @see com.databricks.dicer.external.DicerTestEnvironment#getTotalAttributedLoad
   */
  public double getTotalAttributedLoad(Target target) {
    return scalaTestEnv.getTotalAttributedLoad(target.toScala());
  }

  /**
   * @see com.databricks.dicer.external.DicerTestEnvironment#hasReceivedAtLeast
   */
  public boolean hasReceivedAtLeast(TestAssignmentHandle handle, Clerk<?> clerk) {
    return scalaTestEnv.hasReceivedAtLeast(handle.toScala(), clerk.toScala());
  }

  /**
   * @see com.databricks.dicer.external.DicerTestEnvironment#hasReceivedAtLeast
   */
  public boolean hasReceivedAtLeast(TestAssignmentHandle handle, Slicelet slicelet) {
    return scalaTestEnv.hasReceivedAtLeast(handle.toScala(), slicelet.toScala());
  }

  /**
   * @see com.databricks.dicer.external.DicerTestEnvironment#unfreezeAssignment
   */
  public CompletionStage<Void> unfreezeAssignment(Target target) {
    return FutureConverters.toJava(scalaTestEnv.unfreezeAssignment(target.toScala()))
        .thenApply(ready -> null);
  }

  /**
   * @see com.databricks.dicer.external.DicerTestEnvironment#stop()
   */
  public void stop() {
    scalaTestEnv.stop();
  }

  /** Stops the given Slicelet for testing purposes. */
  public void stopSlicelet(Slicelet slicelet) {
    DicerClientTestInterop.stopSliceletForTest(slicelet.toScala());
  }

  /** Stops the given Clerk for testing purposes. */
  public void stopClerk(Clerk<?> clerk) {
    DicerClientTestInterop.stopClerkForTest(clerk.toScala());
  }
}
